import{_ as a,o as b,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"4.艺术性语言入门手册","description":"","frontmatter":{},"headers":[],"relativePath":"6.STG/4.艺术性语言入门手册.md","filePath":"6.STG/4.艺术性语言入门手册.md"}'),o={name:"6.STG/4.艺术性语言入门手册.md"};function s(l,e,_,h,d,i){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"_4-艺术性语言入门手册",tabindex:"-1"},[p("4.艺术性语言入门手册 "),r("a",{class:"header-anchor",href:"#_4-艺术性语言入门手册","aria-label":'Permalink to "4.艺术性语言入门手册"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001A")])])],-1),n('<h1 id="艺术性语言入门手册" tabindex="-1">艺术性语言入门手册 <a class="header-anchor" href="#艺术性语言入门手册" aria-label="Permalink to &quot;艺术性语言入门手册&quot;">​</a></h1><p>如何判断一段描述/叙述好或不好？<br> 从个人的角度出发，结合当前的剧本及玩家表现综合判断。<br> 什么是氛围感？<br> 通过语言之间的交互，及掷骰来推动剧情。<br> 所谓的氛围感，就是在玩家在游玩的过程中，对ST所开的团有代入感、沉浸感。营造氛围感是一件重要的事情，如果一个剧本的进程之中让玩家感觉到剥离、疏离，那么并不能让他们认为自己真的是在亲身经历一场冒险，而是仍然觉得它仍停留在纸面上，或是电脑屏幕前。</p><p>氛围感如何营造？<br> 运用更富有语言张力的，艺术性的文字来营造。举例而言，在描写一个小镇中，即将到达正午的时间。可以结合时代角度，结合剧本的特殊内容，以具有厚重时代感的方式切入，不必非要以“时间已到正午”之类的简单短句陈述或铺垫。<br> 例：太阳已几乎要升到头顶，它炫目的光正炙烤着大地，而远处教堂的钟声也正穿过干燥的空气传进耳朵里，一连响了十二下。<br> 归根结底，这种方式便是通过侧写其他景物，间接的叙述正在发生的某事。</p><p>而让文字具有艺术性、史诗感，便免不了使用叙述手法，接下来就将介绍一种被称为“双词技巧”的手法。（部分内容引自<a href="https://zhuanlan.zhihu.com/p/463989539" target="_blank" rel="noreferrer">https://zhuanlan.zhihu.com/p/463989539</a>）<br> 首先，引用一段运用了双词技巧的文字以深入讲解：<br> “巨人子孙的毁灭者<br> 在银鸥草原的结实野牛面前碰碎。<br> 上帝亦是如此，此时晚钟的守护人正在暗泣。<br> 岸边的游隼被解体。<br> 对于它来说，希腊人的国王，<br> 并不比在礁石上奔跑的马高贵。”<br> 在这段诗歌中，远端联想的修饰词用于修饰主体内容，将诗意的比喻引入其中。而最显著的特点便是将一种事物比喻成另一种类似的事物，它们有共同特点或相似之处，通过比喻将它们连接起来。<br> 如果将这段诗歌进行重新编译，让它更符合简洁易懂的形式，那么将可以看出：<br> 巨人子孙的毁灭者、晚钟的守护人、希腊的国王都是在代指某人，而银鸥草原的结实野牛、岸边的游隼、礁石上奔跑的马则是在代指残破的船。去除层层修饰的掩蔽后，它的真实面目也被我们所看清。<br> 实际上，它是对于某种事物的再度加工，突显出它具有成比事物的某些特征。<br> 以此类推，假设我们要写血液，便可以用“亡者的遗泪”或是“死神的杯中物”来比喻。<br> 用两种或者多种意象去比喻同一种事物，起到形容、修饰的作用。</p><p>双词技巧可以为玩家提供更丰富的画面感，氛围感与画面感密不可分。而营造画面感，则需要用非常显著的信息去吸引他们的眼球。<br> 举例而言：<br> 两个人正在进行古典的骑士决斗，从蹲在地上打闹的顽童切入，小孩子不懂事，到处乱跑，误入决斗现场，他们打闹推搡着，甚至有人捡起了两位骑士在决斗前扔下的手套，用二人之间的沉默紧张对峙，和顽童的嬉笑打闹作对比，当顽童捡起地上的手套，并将它高高举起时，两位骑士开始了他们的决斗。<br> 用一个跟目前发生的事相关的事，侧面描写正在发生的事，来提供画面感。</p><p>超验-共感<br> 超越经验，超越人类在积累过程中产生的固有思维，超越经验，所不可言说之事，只可意会之事。超验在你单方面获得后，通过共感传递这种你不可言说的感情给玩家。<br> 虽然可以理解，但无法说出来的感情，是一种欲辨已忘言的境界，也可以用另一个词“Biblical style”来形容，用中文来讲便是“微言大义”，用很少的修饰，去直接的抒发你的情感。<br> 无论是超验，还是超验后带给其他玩家的共感，本质上都是一种Prose poem，是感情诗意化的体现，它是发自内心所得到的，通过你所希望表达的方式，传达给你的玩家。而通过共感对于超验进行描述的过程，也就是所谓的超验绘画，用朦胧的或是清晰的，用冷峻的或是温柔的方式，将你的意志超验绘画而出，表达你的情感、心境、想法，用情感去交互。</p><p>戏剧性与张力<br> 什么是戏剧性？<br> 作为一个主持人兼观众，你在第四面墙观看着里面，而他们在三面墙之内活动，推动着故事的发展，起承转合，掀起波澜，这就是戏剧性。<br> 而营造戏剧性有多种方法，其中一种表示使用夸张的比喻，用超前的意象。<br> 什么是夸张的比喻？夸张的比喻并不仅限于比喻，它还可以包括感情模拟。<br> 举例而言：（周围一片黑暗）你只觉得，周围似结了霜的空气令你胆寒，似乎你的勇气，连着落日那早已不见踪影的余晖一起消失了。<br> 假借某人自身之口，模拟某人的感情，假写出某人心理。<br> 再举例而言：就算是历经了无数次失败与循环的西西弗斯，也会认为即使是目前境遇，他也会对你表示同情。<br> 这种手法是通过比喻、引入他人情感，对被描写者的情感进行侧写。</p><p>用他物衬托当前的境遇<br> 举例而言：就连野地里长着的，粗藤蔓的花都知道，它们叫嚣着，扭动着，只为再多吸收一点阳光和水分。虽然在寒冷、漆黑的荒原中，这种比喻并不合时宜。<br> 用花（生命的象征），（有一首名为《Where have all the flowers gone》的歌中，就将花儿（flowers）、战争（war）和坟墓（graveyard）联系在一起）和寒冷的荒原（如北极冻原上是鲜会有生命存在的），在寒冷的荒原上用花作比喻，用喧嚣的生命来反衬寂静的死亡，虽然并不真的有花，只是一种比喻，但这种夸张的比喻也带来了足够的戏剧张力。</p><p>而第三种，则是从人的感官上出发，进行夸张的叙述。人有五感，它的每个感官都会在一个环境之中产生作用，让某个感官暂时失效，从而突出另一种感官，对当前环境进行夸张描写。<br> 举例而言：处在一片漆黑之中，视觉暂时失效。<br> 虽然你的漆黑的瞳仁正在逐渐适应与它同一般漆黑的夜，但很明显，在你完全适应它之前，你只能听到不远处，正不断拍击海岸的滚滚涛声。<br> 先利用环境剥夺其中一种感官，然后再用一种能吸引其注意力的事物，将其思绪引向你所希望表达的部分。能给玩家一个明确的，你想引导的方向。</p><p>超前意象<br> 举例而言：路过一栋大楼，你会想到它在未来的某个时间里，总会风干灰化成一堆残垣败壁、破砖烂瓦。而它那粉刷洁白的骄傲的墙壁，最终也会变成老鼠的避风港。<br> 超前意象，简而言之就是不发生在当前纬度的，也有可能不会发生在将来某时刻的事情，但你做出了这种假设。<br> 这是一种时间与空间的错位，即使在此时此刻，也有可能会在将来的某个时间发生你可能猜想的内容，即使它有可能永远也不会发生。<br> 看到一棵树，就想到它会被做成船。看到金子，就联想到奢侈的生活，等等等等。这也是一种超前想象，跳脱出已有的框架，表达你所想表达的。</p><p>梦意象<br> 人总会做梦。梦是对于光怪陆离的现实的一种寄托和纠正。将现实装进梦里，让所有玩家觉得不合理的事更加不合理。<br> 如何使用梦？<br> 梦的第一个作用是统览总结今天所发生的。梦的特点可以用红楼梦第一回来概括“甄士隐、贾雨村”。也就是所谓的去真存伪，虽然玩家知道这是个梦，也确信这是个梦，但它看起来还是像真的。它和周围的一切，和真实的世界没有任何不同。这是它“真”的地方，是它现实的地方。接下来要明确究竟“魔幻”在哪，“伪”在哪，它真正魔幻在你所想表达的。<br> 而它的第二个作用便是营造反差感，此时，你可以将“伪”的部分放在前面，再用无情的、冰冷赤裸的现实击碎它。<br> 举例而言，戎马半生的男人在梦里回到了记忆角落里，儿时家乡旁青葱的绿草地，天空中只有白云和骄阳，他恍然间，认为自己只是个农夫或者牧者，本应该平静的过完这一生，生老病死，人之常情。<br> 玩家所认为不可能发生的，或者不希望其发生的真的发生，去真存伪，将真的事藏起来，将假的事露出来，在现实中构造超现实。梦想中的，希望得到而得不到的。</p><p>意象的完整性<br> 在前讲述了什么，便在后面照应什么。预示什么，便补全什么。<br> 举例而言：花在一片死亡般寂静的荒原上。<br> 在语句中提到了生命，便需要以死亡来补充它的完整。死亡在哪？死亡就是你想表达的，它就藏在现实之中。一个意象放在幻想之中，用夸张的比喻、超前的意象去表达一个，用现实表达另一个。<br> 成对出现的意象，先后都会出现，甚至是同时出现。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const m=a(o,[["render",s]]);export{f as __pageData,m as default};
